import React from "react";

export default function About() {
  return (
    <section
      id="about"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40",
        scrollMarginTop: "70px"
      }}
    >
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: "clamp(2rem, 6vw, 6rem)",
          alignItems: "center"
        }}
        className="about-grid"
      >
        {/* Left — image */}
        <div
          style={{
            position: "relative",
            aspectRatio: "3 / 4",
            maxWidth: "420px",
            width: "100%"
          }}
        >
          {/* TODO: Replace this placeholder with your headshot image */}
          {/* <img src="/headshot.jpg" alt="Yair Berger" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "0.75rem" }} /> */}
          <div
            style={{
              width: "100%",
              height: "100%",
              background: "#242840",
              border: "1px solid #252A40",
              borderRadius: "0.75rem",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: "0.75rem",
              position: "relative",
              overflow: "hidden"
            }}
          >
            {/* Grid pattern */}
            <div
              aria-hidden="true"
              style={{
                position: "absolute",
                inset: 0,
                backgroundImage:
                  "linear-gradient(#252A40 1px, transparent 1px), linear-gradient(90deg, #252A40 1px, transparent 1px)",
                backgroundSize: "40px 40px",
                opacity: 0.18
              }}
            />
            <svg
              width="48"
              height="48"
              viewBox="0 0 24 24"
              fill="none"
              stroke="#252A40"
              strokeWidth="1.5"
              aria-hidden="true"
              style={{ zIndex: 1 }}
            >
              <circle cx="12" cy="8" r="4" />
              <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
            </svg>
            <p
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.12em",
                textTransform: "uppercase",
                color: "#3A3A5E",
                zIndex: 1
              }}
            >
              Headshot coming
            </p>
          </div>

          {/* Social handles */}
          <div
            style={{
              position: "absolute",
              bottom: "-1.5rem",
              left: 0,
              right: 0,
              display: "flex",
              gap: "0.75rem",
              justifyContent: "center"
            }}
          >
            {/* TODO: Replace # with your Instagram URL */}
            <a
              href="#"
              target="_blank"
              rel="noopener noreferrer"
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.1em",
                textTransform: "uppercase",
                color: "#8A8AB0",
                textDecoration: "none",
                transition: "color 0.15s ease"
              }}
              onMouseEnter={e => e.currentTarget.style.color = "#5B8DEF"}
              onMouseLeave={e => e.currentTarget.style.color = "#8A8AB0"}
            >
              @instagram_handle
            </a>
            <span style={{ color: "#252A40" }}>·</span>
            {/* TODO: Replace # with your TikTok URL */}
            <a
              href="#"
              target="_blank"
              rel="noopener noreferrer"
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.65rem",
                letterSpacing: "0.1em",
                textTransform: "uppercase",
                color: "#8A8AB0",
                textDecoration: "none",
                transition: "color 0.15s ease"
              }}
              onMouseEnter={e => e.currentTarget.style.color = "#5B8DEF"}
              onMouseLeave={e => e.currentTarget.style.color = "#8A8AB0"}
            >
              @tiktok_handle
            </a>
          </div>
        </div>

        {/* Right — text */}
        <div style={{ paddingTop: "1rem" }}>
          <p className="eyebrow mb-4">About</p>
          <h2
            style={{
              fontFamily: "'Space Grotesk', sans-serif",
              fontSize: "clamp(1.6rem, 3.5vw, 2.8rem)",
              fontWeight: 700,
              letterSpacing: "-0.025em",
              color: "#F0F0EC",
              lineHeight: 1.1,
              marginBottom: "2rem"
            }}
          >
            I didn't want to work harder.<br />
            <span style={{ color: "#5B8DEF" }}>So I built AI that works for me.</span>
          </h2>

          <div
            style={{
              display: "flex",
              flexDirection: "column",
              gap: "1.25rem"
            }}
          >
            {[
              "I'm Yair. Husband to the most amazing wife, father to the most energetic and perfect little girl Mia, and dog dad to the goofiest dog Krembo.",
              "Life gets busy. Like really busy. Between work, daycare runs, bedtime routines, and trying to actually show up for the people you love, the days just disappear.",
              "I've been building AI systems for a while now, always for the companies I worked for. And at some point I just thought, why am I not using this for myself?",
              "So I did. I started automating the stuff that was eating my time. And it worked. Like actually worked. So I started helping other individuals do the same, and that worked well too.",
              "Now, drawing on years of experience working across startups and with leadership teams, I help individuals, business owners, and startups use AI to get their time back, cut costs, and move faster.",
              "Nobody should be drowning in their to-do list when AI can handle half of it."
            ].map((para, i) => (
              <p
                key={i}
                style={{
                  fontFamily: "'Inter', sans-serif",
                  fontSize: "0.95rem",
                  color: i === 5 ? "#F0F0EC" : "#8A8AB0",
                  lineHeight: 1.75,
                  fontWeight: i === 5 ? 500 : 400
                }}
              >
                {para}
              </p>
            ))}
          </div>
        </div>
      </div>

      {/* Mobile responsive styles */}
      <style>{`
        @media (max-width: 768px) {
          .about-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </section>
  );
}
